import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse(`{"title":"12. Redundancy","description":"","frontmatter":{"title":"12. Redundancy","eba":"Children's Services Award 2010","topics":["hours","penalty-rates","shift-work","employment","redundancy","termination","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/employment/12-redundancy.md","filePath":"ebas/childrens-services/employment/12-redundancy.md"}`),r={name:"ebas/childrens-services/employment/12-redundancy.md"};function i(p,e,s,l,d,c){return o(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="_12-redundancy" tabindex="-1">12. Redundancy <a class="header-anchor" href="#_12-redundancy" aria-label="Permalink to &quot;12. Redundancy&quot;">​</a></h1><p>NOTE: Redundancy pay is provided for in the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>. See sections 119--123 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><ol><li><p>Transfer to lower paid duties on redundancy</p><p>a. Clause 12.1 applies if, because of redundancy, an employee is transferred to new duties to which a lower ordinary rate of pay applies.</p><p>b. The employer may:</p><pre><code>i.  give the employee notice of the transfer of at least the
    same length as the employee would be entitled to under
    section 117 of the
    [Act](http://www.legislation.gov.au/Series/C2009A00028) as
    if it were a notice of termination given by the employer; or

ii. transfer the employee to the new duties without giving
    notice of transfer or before the expiry of a notice of
    transfer, provided that the employer pays the employee as
    set out in paragraph (c).
</code></pre><p>c. If the employer acts as mentioned in paragraph (b)(ii), the employee is entitled to a payment of an amount equal to the difference between the ordinary rate of pay of the employee (inclusive of all-purpose allowances, shift rates and penalty rates applicable to ordinary hours) for the hours of work the employee would have worked in the first role, and the ordinary rate of pay (also inclusive of all-purpose allowances, shift rates and penalty rates applicable to ordinary hours) of the employee in the second role for the period for which notice was not given.</p></li><li><p>Employee leaving during redundancy notice period</p><p>a. An employee given notice of termination in circumstances of redundancy may terminate their employment during the minimum period of notice prescribed by section 117(3) of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p>b. The employee is entitled to receive the benefits and payments they would have received under clause 12 or under sections 119--123 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> had they remained in employment until the expiry of the notice.</p><p>c. However, the employee is not entitled to be paid for any part of the period of notice remaining after the employee ceased to be employed.</p></li><li><p>Job search entitlement</p><p>a. Where an employer has given notice of termination to an employee in circumstances of redundancy, the employee must be allowed time off without loss of pay of up to one day each week of the minimum period of notice prescribed by section 117(3) of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> for the purpose of seeking other employment.</p><p>b. If an employee is allowed time off without loss of pay of more than one day under paragraph (a), the employee must, at the request of the employer, produce proof of attendance at an interview.</p><p>c. A statutory declaration is sufficient for the purpose of paragraph (b).</p><p>d. An employee who fails to produce proof when required under paragraph (b) is not entitled to be paid for the time off.</p><p>e. This entitlement applies instead of <a href="/eba/ebas/childrens-services/employment/11-termination-of-employment.html">clauses 11</a>.2 and 11.3.</p></li></ol><p>Plain language terms: redundancy pay, retrenchment.</p>`,4)])])}const m=t(r,[["render",i]]);export{f as __pageData,m as default};
